import React from 'react';
import clsx from 'clsx';
import type { TextBadgeSidecarComponentType } from './types';
import { defaults, getBadgeFont, isPresetColor, measureText } from './utils';
import { useCssScope } from '../config-provider/hooks';

export function createSVGTextBadgeSidecar({
  textVerticalAlign = 'baseline',
  size = defaults.textBadgeFontSize,
  fontSize = 10,
}: {
  /**
   * @defaultValue `baseline`
   */
  textVerticalAlign?: 'baseline' | 'center';
  size?: number;
  fontSize?: number;
} = {}) {
  const SVGTextBadgeSidecar: TextBadgeSidecarComponentType = ({ color, content, className, style }) => {
    const font = getBadgeFont(fontSize);
    const cssScope = useCssScope('badge');
    const textMetrics = React.useMemo(() => measureText(content, font), [content, font]);
    const tw = textMetrics.width;
    const th = textMetrics.actualBoundingBoxAscent + textMetrics.actualBoundingBoxDescent;

    const ch = size;

    const d = ch;
    const r = d / 2;

    const paddingX = (r * 4) / 7;
    const isCircle = tw < r * 2 - paddingX * 2 || [...content].length === 1;
    const cw = (() => {
      if (isCircle) {
        return d;
      }
      return tw + paddingX * 2;
    })();

    const textProps: React.SVGProps<SVGTextElement> = {};
    if (textVerticalAlign === 'baseline') {
      textProps.dominantBaseline = 'central';
      textProps.y = ch / 2;
    } else {
      // y + descent = (ch + th) / 2
      textProps.dominantBaseline = 'alphabetic';
      textProps.y = (ch + th) / 2 - textMetrics.actualBoundingBoxDescent;
    }

    return (
      <svg
        style={style}
        width={cw}
        height={ch}
        className={clsx(className, cssScope('__badge-mode-svg'))}
        viewBox={`0 0 ${cw} ${ch}`}
      >
        <rect
          x={0}
          y={0}
          width={cw}
          height={ch}
          rx={ch / 2}
          ry={ch / 2}
          style={
            isPresetColor(color)
              ? undefined
              : {
                  fill: color,
                }
          }
        />
        <text x="50%" textAnchor="middle" {...textProps}>
          {content}
        </text>
      </svg>
    );
  };
  return SVGTextBadgeSidecar;
}

export const SVGTextBadgeSidecar = createSVGTextBadgeSidecar();
